"use strict";(self.webpackChunkportfolio=self.webpackChunkportfolio||[]).push([[3406],{8063:o=>{o.exports=JSON.parse('{"blogPosts":[{"id":"introduction","metadata":{"permalink":"/portfolio/blog/introduction","source":"@site/blog/2023-01-21-introduction/index.md","title":"Introduction","description":"I would like to take a coffe with you and sit to draw & think.","date":"2023-01-21T00:00:00.000Z","formattedDate":"January 21, 2023","tags":[],"readingTime":0.46,"hasTruncateMarker":false,"authors":[{"name":"Juan Carlos","title":"Arroyo Sosa","url":"https://github.com/jcarroyos","imageURL":"https://avatars.githubusercontent.com/u/4398275","key":"jcarroyos"}],"frontMatter":{"slug":"introduction","title":"Introduction","authors":["jcarroyos"],"tags":[]},"nextItem":{"title":"Virtual enviroments at MMGP","permalink":"/portfolio/blog/virtual-enviroment-unal"}},"content":"I would like to take a coffe with you and sit to draw & think.\\n\\nLet me tell you that if I were to exhibit my last years works, it would undoubtedly be a exploration, an invitation to despertar your curiosity of information architectures, diagrams, data visualizations and user interfaces, with explanatory notes on complex social issues.\\n\\nThe hard work will be to remember all names of friends, physicists, economists, communicators, political scientists, sociologists, social leaders and human rights defenders with whom I have had the honor of sitting down to think."},{"id":"virtual-enviroment-unal","metadata":{"permalink":"/portfolio/blog/virtual-enviroment-unal","source":"@site/blog/2021-06-30-virtual-enviroment/index.md","title":"Virtual enviroments at MMGP","description":"How do museums take advantage of information technologies and virtual environments? Well, based on this question, a pedagogical experience was created for the fifth, sixth and seventh cohorts of the Master\'s Degree in Museology and Heritage Management at the National University of Colombia, the name of the course is, ... to no one\'s surprise \ud83d\ude0c, INFORMATION TECHNOLOGIES AND VIRTUAL ENVIRONMENTS.","date":"2021-06-30T00:00:00.000Z","formattedDate":"June 30, 2021","tags":[{"label":"tics","permalink":"/portfolio/blog/tags/tics"},{"label":"museology","permalink":"/portfolio/blog/tags/museology"}],"readingTime":0.695,"hasTruncateMarker":false,"authors":[{"name":"Juan Carlos","title":"Arroyo Sosa","url":"https://github.com/jcarroyos","imageURL":"https://avatars.githubusercontent.com/u/4398275","key":"jcarroyos"}],"frontMatter":{"slug":"virtual-enviroment-unal","title":"Virtual enviroments at MMGP","authors":["jcarroyos"],"tags":["tics","museology"]},"prevItem":{"title":"Introduction","permalink":"/portfolio/blog/introduction"},"nextItem":{"title":"Infographics at UTolima","permalink":"/portfolio/blog/infographics-utolima"}},"content":"How do museums take advantage of information technologies and virtual environments? Well, based on this question, a pedagogical experience was created for the fifth, sixth and seventh cohorts of the Master\'s Degree in [Museology and Heritage Management at the National University of Colombia](http://artes.bogota.unal.edu.co/programas-academicos/posgrado/maestria/museologia), the name of the course is, ... to no one\'s surprise \ud83d\ude0c, INFORMATION TECHNOLOGIES AND VIRTUAL ENVIRONMENTS.\\n\\nThis course was shared with other teachers, in the first cohorts it was taught together with Philippe Boland and Ana Mar\xeda Moreno Ballesteros. The course of the year 2021 I worked together with [Paola Parra](https://www.linkedin.com/in/paoltricia).\\n\\n[Click here to see the course program (in spanish)](./program-mmgp-jcarroyos-paoltricia.pdf)\\n\\n## Class pics\\n\\n:::note Ideation process\\n![registro de clase mmgp](./mmgp-1.jpg)\\n\\n:::\\n\\n:::note Dashboard snapshot\\n![registro de clase mmgp](./mmgp-2.jpg)\\n:::\\n\\n:::note structuring information workshop\\n![registro de clase mmgp](./mmgp-3.jpg)\\n:::\\n\\n:::note coding\\n![registro de clase mmgp](./mmgp-4.jpg)\\n:::"},{"id":"infographics-utolima","metadata":{"permalink":"/portfolio/blog/infographics-utolima","source":"@site/blog/2021-01-30-infographics/index.md","title":"Infographics at UTolima","description":"From 2016 to 2021 I had the beautiful experience in the role of professor for Infographics at University of Tolima. I learned and shared a lot during those years of teaching.","date":"2021-01-30T00:00:00.000Z","formattedDate":"January 30, 2021","tags":[{"label":"infographics","permalink":"/portfolio/blog/tags/infographics"}],"readingTime":0.785,"hasTruncateMarker":false,"authors":[{"name":"Juan Carlos","title":"Arroyo Sosa","url":"https://github.com/jcarroyos","imageURL":"https://avatars.githubusercontent.com/u/4398275","key":"jcarroyos"}],"frontMatter":{"slug":"infographics-utolima","title":"Infographics at UTolima","authors":["jcarroyos"],"tags":["infographics"]},"prevItem":{"title":"Virtual enviroments at MMGP","permalink":"/portfolio/blog/virtual-enviroment-unal"}},"content":"From 2016 to 2021 I had the beautiful experience in the role of professor for **Infographics** at [University of Tolima](https://ut.edu.co/). I learned and shared a lot during those years of teaching.\\n\\nWith a practical approach, this course presents the evolution of infographics, the workshop focus on the core questions:\\n\\n- what is infographics?\\n- what are infographics for?\\n- and how we can made infographics?\\n\\nBased on the idea that infographics in the field of communication can be understood as a journalistic genre, during the course we explore the possibilities of creation and think on the theoretical field of image research and visual studies.\\n\\n## Class pics\\n\\n:::note Student project analog infographics\\n![registro de clase infograf\xeda](./utolima-infografia-1.jpg)\\n:::\\n\\n:::note Data collecting in public space\\n![registro de clase infograf\xeda](./utolima-infografia-2.jpg)\\n:::\\n\\n:::note Data collecting in public space\\n![registro de clase infograf\xeda](./utolima-infografia-3.jpg)\\n:::\\n\\n:::note Workshop at https://tell.com.co/\\n![registro de clase infograf\xeda](./utolima-infografia-4.jpg)\\n:::\\n\\n:::note Workshop at https://www.lasillavacia.com/\\n![registro de clase infograf\xeda](./utolima-infografia-5.jpg)\\n:::"}]}')}}]);